frappe.query_reports["Report Purchase Invoice VS  Purchase Receipt"] = {
    onload: function(report) {
        report.columns.forEach(col => {
            if (col.label === "Linked to Purchase Receipt") {
                col.format = (value) => {
                    if (value === "Yes") {
                        return `<span style="color:green; font-weight:bold;">${value}</span>`;
                    } else if (value === "No") {
                        return `<span style="color:red; font-weight:bold;">${value}</span>`;
                    }
                    return value;
                };
            }
        });
    }
};

frappe.query_reports["Report Sales Invoice VS  Delivery Note"] = {
    "formatter": function (value, row, column, data, default_formatter) {
        value = default_formatter(value, row, column, data);

        // Bold all values
        value = `<b>${value}</b>`;

        // Add color to "Delivery Status"
        if (column.fieldname === "Delivery Status") {
            if (value.includes("Not Delivered")) {
                value = `<span style="color:red;"><b>${value}</b></span>`;
            } else if (value.includes("Partially Delivered")) {
                value = `<span style="color:orange;"><b>${value}</b></span>`;
            } else if (value.includes("Fully Delivered")) {
                value = `<span style="color:green;"><b>${value}</b></span>`;
            }
        }

        return value;
    }
};
